import bisect
class Solution:
    def solve(self, nums: List[int]) -> int:
        sub = []
        for x in nums:
            if not sub or x > sub[-1]:
                sub.append(x)
            else:
                idx = bisect.bisect_left(sub, x)
                sub[idx] = x
        return len(sub)

